// Helper: get asset by symbol
export function getAssetBySymbol(symbol: string): Asset | undefined {
  return ALL_ASSETS.find(a => a.symbol === symbol || a.id === symbol.toLowerCase());
}

// Helper: search assets
export function searchAssets(query: string, limit = 10): Asset[] {
  if (!query.trim()) return [];
  const q = query.toLowerCase();
  return ALL_ASSETS.filter(
    a => a.symbol.toLowerCase().includes(q) ||
         a.name.toLowerCase().includes(q) ||
         a.category.toLowerCase().includes(q) ||
         a.exchange.toLowerCase().includes(q)
  ).slice(0, limit);
}
